@Test
  public void componentsSeparatedBy() throws Exception {
    List<Object> stuff = new ArrayList<>();
    stuff.add(Boolean.TRUE);
    stuff.add(1.0f);
    String output = StringUtils.componentsSeparatedBy(stuff, ",");
    assertEquals("true,1.0", output);
  }

